假设英文句子由若干词构成。下面 C++ 代码统计输出的词数是（ ）。

```cpp
int main()
{
    string str="gEsP is Interesting !";
    int x = str.length();
    int nwords = 0;
    for(int i = 0; i < x; i++)
        if (str[i]==' '){
            nwords++;
            while(str[++i]==' ') ;
        }
    cout << nwords << endl;
    cout << endl;
    return 0;
}
```

下面 C++ 程序执行的结果是（ ）。

```cpp
int main()
{
    int a[20], i;
    int cnt = 0;
    for (i = 0; i < 20; i++)
        a[i] = i + 1;
    for ( ; i > 1; i--)
        if ((a[i - 1] + a[i - 2]) % 3)
            cnt++;
    cout << cnt << endl;
    cout << endl;
    return 0;
}
```

下面 C++ 代码可以计算 $1$ 到 $100$ 的累加和，采用的是穷举法。

```cpp
int main()
{
    int i, sum = 0;
    for (int i = 1; i <= 100; i++)
        sum += i;
    cout << sum << endl;
    cout << endl;
    return 0;
}
```

